import React, { useState } from 'react';
import { User, UserRole } from '../types';
import Logo from './Logo';
import Footer from './Footer';
import { motion, AnimatePresence } from 'framer-motion';

interface LayoutProps {
  children: React.ReactNode;
  onNavigate: (view: any) => void;
  activeView: string;
  user: User | null;
  onLogout: () => void;
  onLogoClick?: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, onNavigate, activeView, user, onLogout, onLogoClick }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const handleNav = (view: any) => {
    onNavigate(view);
    setIsMenuOpen(false);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <nav className="fixed top-0 left-0 right-0 z-50 bg-white/90 backdrop-blur-xl shadow-sm border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6 lg:px-8 h-20 md:h-24 flex items-center justify-between">
          <div 
            className="cursor-pointer" 
            onClick={() => {
              onNavigate('home');
              if (onLogoClick) onLogoClick();
            }}
          >
            <Logo className="w-10 h-10 md:w-12 md:h-12" />
          </div>

          {/* Desktop Navigation */}
          <div className="hidden md:flex items-center space-x-12">
            <button 
              onClick={() => onNavigate('home')} 
              className={`text-[11px] font-black uppercase tracking-[0.2em] transition-all hover:text-gold ${activeView === 'home' ? 'text-charcoal border-b-2 border-gold pb-1' : 'text-gray-400'}`}
            >
              Home
            </button>
            <button 
              onClick={() => onNavigate('quiz')} 
              className={`text-[11px] font-black uppercase tracking-[0.2em] transition-all hover:text-gold ${activeView === 'quiz' ? 'text-charcoal border-b-2 border-gold pb-1' : 'text-gray-400'}`}
            >
              Assessment
            </button>

            {user ? (
              <>
                <button 
                  onClick={() => onNavigate('dashboard')} 
                  className={`text-[11px] font-black uppercase tracking-[0.2em] transition-all hover:text-gold ${activeView === 'dashboard' ? 'text-charcoal border-b-2 border-gold pb-1' : 'text-gray-400'}`}
                >
                  Dashboard
                </button>
                {user.role === UserRole.ADMIN && (
                  <button 
                    onClick={() => onNavigate('manager')} 
                    className={`text-[11px] font-black uppercase tracking-[0.2em] transition-all hover:text-gold ${activeView === 'manager' ? 'text-charcoal border-b-2 border-gold pb-1' : 'text-gray-400'}`}
                  >
                    Inventory
                  </button>
                )}
                <button onClick={onLogout} className="text-[11px] font-black uppercase tracking-[0.2em] text-red-500 hover:text-red-700">Logout</button>
              </>
            ) : (
              <button 
                onClick={() => onNavigate('login')} 
                className="bg-charcoal text-white px-10 py-3.5 rounded-full text-[11px] font-black uppercase tracking-[0.2em] transition-all hover:bg-black shadow-lg shadow-gray-100"
              >
                Faculty Login
              </button>
            )}
          </div>

          {/* Mobile Hamburger Menu Button */}
          <button 
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            className="md:hidden flex flex-col space-y-1.5 p-2 focus:outline-none z-[60]"
            aria-label="Toggle Menu"
          >
            <motion.div 
              animate={isMenuOpen ? { rotate: 45, y: 7.5 } : { rotate: 0, y: 0 }}
              className="w-7 h-0.5 bg-charcoal rounded-full origin-center"
            />
            <motion.div 
              animate={isMenuOpen ? { opacity: 0, x: 10 } : { opacity: 1, x: 0 }}
              className="w-7 h-0.5 bg-charcoal rounded-full"
            />
            <motion.div 
              animate={isMenuOpen ? { rotate: -45, y: -7.5 } : { rotate: 0, y: 0 }}
              className="w-7 h-0.5 bg-charcoal rounded-full origin-center"
            />
          </button>
        </div>

        {/* Mobile Navigation Drawer */}
        <AnimatePresence>
          {isMenuOpen && (
            <>
              {/* Professional Overlay / Backdrop */}
              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                onClick={() => setIsMenuOpen(false)}
                className="fixed inset-0 bg-slate-900/60 backdrop-blur-[2px] z-[55] md:hidden"
              />

              {/* Mobile Sidebar - Solid Gray-White Background */}
              <motion.div 
                initial={{ x: '100%' }}
                animate={{ x: 0 }}
                exit={{ x: '100%' }}
                transition={{ type: 'spring', damping: 28, stiffness: 220 }}
                className="fixed top-0 right-0 bottom-0 w-[300px] bg-[#F8F9FA] z-[56] md:hidden shadow-[-20px_0_60px_-15px_rgba(0,0,0,0.15)] border-l border-white flex flex-col"
              >
                <div className="p-8 border-b border-slate-200/50 bg-white/50">
                  <Logo hideText className="w-8 h-8" />
                  <p className="mt-4 text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">Navigator</p>
                </div>

                <div className="flex flex-col pt-10 px-8 space-y-2">
                  <button 
                    onClick={() => handleNav('home')}
                    className={`flex items-center space-x-4 p-4 rounded-2xl transition-all ${activeView === 'home' ? 'bg-wellBeingBlue text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200/50'}`}
                  >
                    <span className="text-sm font-black uppercase tracking-widest">Home</span>
                  </button>

                  <button 
                    onClick={() => handleNav('quiz')}
                    className={`flex items-center space-x-4 p-4 rounded-2xl transition-all ${activeView === 'quiz' ? 'bg-wellBeingBlue text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200/50'}`}
                  >
                    <span className="text-sm font-black uppercase tracking-widest">Assessment</span>
                  </button>

                  {user && (
                    <>
                      <button 
                        onClick={() => handleNav('dashboard')}
                        className={`flex items-center space-x-4 p-4 rounded-2xl transition-all ${activeView === 'dashboard' ? 'bg-wellBeingBlue text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200/50'}`}
                      >
                        <span className="text-sm font-black uppercase tracking-widest">Dashboard</span>
                      </button>

                      {user.role === UserRole.ADMIN && (
                        <button 
                          onClick={() => handleNav('manager')}
                          className={`flex items-center space-x-4 p-4 rounded-2xl transition-all ${activeView === 'manager' ? 'bg-wellBeingBlue text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200/50'}`}
                        >
                          <span className="text-sm font-black uppercase tracking-widest">Inventory</span>
                        </button>
                      )}

                      <button 
                        onClick={onLogout}
                        className="flex items-center space-x-4 p-4 rounded-2xl text-red-500 hover:bg-red-50 transition-all mt-4"
                      >
                        <span className="text-sm font-black uppercase tracking-widest">Sign Out</span>
                      </button>
                    </>
                  )}

                  {!user && (
                    <div className="pt-10">
                      <button 
                        onClick={() => handleNav('login')}
                        className="w-full bg-charcoal text-white px-8 py-5 rounded-[2rem] text-xs font-black uppercase tracking-widest text-center shadow-xl hover:bg-black transition-all"
                      >
                        Faculty Login
                      </button>
                    </div>
                  )}
                </div>

                <div className="mt-auto p-8 border-t border-slate-200/50 text-center">
                  <p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.3em]">NitGyanam Well-Being v2.0</p>
                </div>
              </motion.div>
            </>
          )}
        </AnimatePresence>
      </nav>

      <main className="flex-grow pt-20 md:pt-24">
        {children}
      </main>

      <Footer />
    </div>
  );
};

export default Layout;

import path from 'path';
import { defineConfig, loadEnv } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig(({ mode }) => {
    // Fix: Replaced process.cwd() with '.' to avoid "Property 'cwd' does not exist" type error and target current project root
    const env = loadEnv(mode, '.', '');

    // Mapping keys to process.env for the build
    const config = {
      apiKey: env.VITE_GEMINI_API_KEY || env.API_KEY || "",
      supabaseUrl: env.VITE_SUPABASE_URL || env.SUPABASE_URL || "",
      supabaseKey: env.VITE_SUPABASE_ANON_KEY || env.SUPABASE_ANON_KEY || ""
    };

    return {
      base: '/',
      server: {
        port: 3000,
        host: '0.0.0.0',
      },
      plugins: [react()],
      define: {
        'process.env.API_KEY': JSON.stringify(config.apiKey),
        'process.env.SUPABASE_URL': JSON.stringify(config.supabaseUrl),
        'process.env.SUPABASE_ANON_KEY': JSON.stringify(config.supabaseKey),
        // Adding VITE_ versions just in case
        'process.env.VITE_SUPABASE_URL': JSON.stringify(config.supabaseUrl),
        'process.env.VITE_SUPABASE_ANON_KEY': JSON.stringify(config.supabaseKey),
      },
      resolve: {
        alias: {
          // Fix: Replaced __dirname with path.resolve('.') as __dirname is not defined in ES modules
          '@': path.resolve('.'),
        }
      },
      build: {
        outDir: 'dist',
        sourcemap: false,
        minify: 'esbuild',
        chunkSizeWarningLimit: 1000,
      }
    };
});

