        else successCount++;
      } catch {
        failedCount++;
      }
    }
    return { success: successCount, failed: failedCount };
  },

  generateAIAnalysis: async (submission: Submission, questions: Question[]): Promise<string> => {
    if (!process.env.API_KEY) {
      return "CRITICAL: API_KEY is missing from environment variables.";
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const answerEntries = Object.entries(submission.answers || {});
      const answerSummary = answerEntries.map(([qid, ans]: [string, any]) => {
        const q = questions.find(q => q.id === qid);
        const opt = q?.options.find(o => o.id === ans.optionId);
        return `[Indicator: ${ans.indicator}] Q: ${q?.textEn} -> Answer: "${opt?.en}"`;
      }).join('\n');

      let ageSpecificGuidelines = "";
      if (submission.level === WellBeingLevel.LEVEL_1) {
        ageSpecificGuidelines = `
          FOCUS: Std 1 to 3
          - CATEGORY 1 (Behaviour): Focus on social circle (friends), attitude towards school, patience/ADHD traits, and empathy.
          - CATEGORY 2 (Mental Health): Morning mindset, baseline self-image, sleep quality, and resilience.
          - CATEGORY 3 (Conclusion Concern): Early signs of isolation, magic shields (fears), and home belonging.
          - CATEGORY 4 (Immediate Action): Neglect markers, escape desires, and total emotional shutdown.
        `;
      } else if (submission.level === WellBeingLevel.LEVEL_2) {
        ageSpecificGuidelines = `
          FOCUS: Std 4 to 6
          - CATEGORY 1 (Behaviour): Academic anxiety, focus, response to failure, and support-seeking behavior.
          - CATEGORY 2 (Mental Health): Internal battery (burnout), life narrative (adventure vs tragedy), and core self-worth.
          - CATEGORY 3 (Conclusion Concern): School perception (playground vs prison), social paranoia, and parentification.
          - CATEGORY 4 (Immediate Action): Anhedonia, environmental instability, dissociation, and loss of future-oriented optimism.
        `;
      } else if (submission.level === WellBeingLevel.LEVEL_3) {
        ageSpecificGuidelines = `
          FOCUS: Std 7 to 8
          - CATEGORY 1 (Behaviour): Authenticity vs Masking, digital habits (Social Media impact), and peer pressure boundaries.
          - CATEGORY 2 (Mental Health): Body image (Mirror), internal voice quality, and somatic stress responses (Physical energy).
          - CATEGORY 3 (Conclusion Concern): Social isolation/rejection sensitivity, parent-child bond quality, and general anxiety/paranoia.
          - CATEGORY 4 (Immediate Action): Red Flags: Suicidal ideation (Critical), self-harm, anhedonia, and severe panic markers.
        `;
      }

      const promptText = `
        Act as a Senior Clinical Psychologist and EdTech Specialist for NitGyanam. 
        Analyze the following student assessment data using our 4-Category Clinical Framework.

        FRAMEWORK CATEGORIES:
        1. BEHAVIOUR PATTERN: Interaction, habits, and social dynamics.
        2. MENTAL HEALTH (INTERNAL STATE): Internal mood, energy, and self-esteem.
        3. CONCLUSION CONCERN: Environmental stressors and growing insecurities.
        4. IMMEDIATE ACTION (RED FLAGS): High-risk indicators (Trauma, abuse, clinical depression).

        AGE-SPECIFIC ANALYSIS GUIDELINES:
        ${ageSpecificGuidelines}

        STUDENT CONTEXT:
        Name: ${submission.student.name}
        Grade: ${submission.student.standard} (${submission.level})
        Overall Risk Status: ${submission.riskStatus}

        RAW FINDINGS (MCQ Responses):
        ${answerSummary}

        TASK:
        Generate a comprehensive Clinical Synthesis Report. 
        Ensure you explicitly address the 4 categories above. 
        Be extremely vigilant for any "RED FLAG" indicators in the answers.

        REPORT STRUCTURE:
        - CLINICAL SUMMARY: A high-level overview of the student's psychological profile.
        - CATEGORICAL BREAKDOWN: Detailed analysis of Behaviour, Mental Health, and Concerns.
        - RISK ASSESSMENT: Specific identification of any Red Flags or clinical warnings.
        - ACTIONABLE RECOMMENDATIONS: Clear next steps for school counselors and parents.
        - FINAL VERDICT: A professional closing statement on the student's well-being.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: promptText,
        config: { 
          temperature: 0.65,
          topP: 0.95,
          topK: 64
        }
      });

      return response.text || "Diagnostic failure - No analysis generated.";
    } catch (error: any) {
      console.error("AI Analysis Error:", error);
      return `Clinical Synthesis Error: ${error?.message || "Internal failure during report generation."}`;
    }
  },

  analyzeResults: (answers: ResponseIndicator[]) => {
    const total = answers.length;
    const redFlagCount = answers.filter(a => a === ResponseIndicator.RED_FLAG).length;
    const concernCount = answers.filter(a => a === ResponseIndicator.CONCERN).length;

