                      {opt.id.toUpperCase()}
                    </div>
                    <div className="flex-grow">
                      <p className={`font-black text-2xl md:text-3xl mb-3 transition-colors tracking-tight leading-tight ${tempOption?.id === opt.id ? 'text-wellBeingGreen' : 'text-slate-800 group-hover:text-wellBeingGreen'}`}>{opt.en}</p>
                      <p className="text-slate-400 font-hindi font-bold text-xl md:text-2xl leading-relaxed italic">{opt.hi}</p>
                    </div>
                  </div>
                </button>
              ))}
            </div>
          </motion.div>
        </AnimatePresence>

        <div className="flex justify-center h-24">
          <AnimatePresence>
            {tempOption && (
              <motion.button 
                initial={{ opacity: 0, scale: 0.8, y: 10 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.8, y: 10 }}
                disabled={isTransitioning}
                onClick={handleNext}
                className={`px-24 py-8 rounded-full font-black uppercase tracking-[0.2em] text-[13px] transition-all shadow-2xl bg-charcoal text-white hover:bg-black active:scale-95`}
              >
                {isLastQuestion ? 'Generate Final Report' : 'Confirm & Next'}
              </motion.button>
            )}
          </AnimatePresence>
        </div>
      </div>
    );
  }

  if (step === 'completed' && finalSubmission) {
    return (
      <motion.div 
        initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }}
        className="max-w-4xl mx-auto px-6 py-20"
