              <h4 className="text-4xl font-black text-charcoal leading-none">{finalSubmission.student.name}</h4>
              <p className="text-slate-400 font-bold uppercase text-[12px] tracking-[0.2em] mt-3">Std {finalSubmission.student.standard} • {finalSubmission.student.school}</p>
