            <div className="md:text-right">
              <p className="text-[12px] font-black uppercase text-slate-400 tracking-widest mb-4">Diagnostic Identifier</p>
              <h4 className="text-3xl font-black text-wellBeingBlue leading-none">{finalSubmission.id}</h4>
              <p className="text-slate-400 font-bold uppercase text-[12px] tracking-[0.2em] mt-3">{new Date(finalSubmission.timestamp).toLocaleString()}</p>
