              const ansData = finalSubmission.answers[q.id] as any;
              const selectedOption = q.options.find(o => o.id === ansData?.optionId);

              return (
                <div key={q.id} className="relative group">
                  <div className="absolute -left-16 top-0 text-slate-100 font-black text-8xl select-none group-hover:text-wellBeingBlue/5 transition-colors">
                    {String(idx + 1).padStart(2, '0')}
                  </div>
