                    </h3>
                    <div className="bg-slate-50/50 border-l-[10px] border-wellBeingBlue p-10 rounded-r-[3rem]">
                      <p className="text-wellBeingBlue font-black text-3xl tracking-tight">
                        {selectedOption?.en}
                      </p>
                      <p className="text-slate-400 font-hindi font-bold mt-4 text-2xl italic">
                        {selectedOption?.hi}
                      </p>
                      <div className="mt-8">
                         <span className={`inline-block text-[10px] font-black uppercase tracking-widest px-4 py-1.5 rounded-full ${
                           selectedOption?.indicator === ResponseIndicator.RED_FLAG ? 'bg-red-50 text-red-500' :
                           selectedOption?.indicator === ResponseIndicator.CONCERN ? 'bg-amber-50 text-amber-500' : 'bg-emerald-50 text-emerald-500'
                         }`}>
                           Status: {selectedOption?.indicator}
                         </span>
                      </div>
                    </div>
                  </div>
