                  className={`bg-white p-10 text-left group rounded-[3rem] border transition-all shadow-sm hover:shadow-xl ${tempOption?.id === opt.id ? 'border-wellBeingGreen bg-wellBeingGreen/[0.03] ring-4 ring-wellBeingGreen/5 scale-[1.02]' : 'border-slate-50 hover:border-wellBeingGreen'}`}
