                      {opt.id.toUpperCase()}
                    </div>
                    <div className="flex-grow">
                      <p className={`font-black text-2xl md:text-3xl mb-2 transition-colors tracking-tight leading-tight ${tempOption?.id === opt.id ? 'text-wellBeingGreen' : 'text-slate-800 group-hover:text-wellBeingGreen'}`}>{opt.en}</p>
                      <p className="text-slate-400 font-hindi font-bold text-lg md:text-xl leading-relaxed italic">{opt.hi}</p>
                    </div>
                  </div>
