        </div>

        <div className="bg-white rounded-[4rem] shadow-soft-xl border border-slate-100 p-12 md:p-24 overflow-hidden relative mb-16">
          <div className="absolute top-0 right-0 p-10 opacity-5 select-none pointer-events-none">
             <span className="text-9xl font-black text-charcoal">SUMMARY</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 mb-20 border-b border-slate-50 pb-20">
