                      <p className="text-wellBeingBlue font-black text-3xl tracking-tight">
                        {selectedOption?.en}
                      </p>
                      <p className="text-slate-400 font-hindi font-bold mt-4 text-2xl italic">
                        {selectedOption?.hi}
                      </p>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div className="text-center py-20 border-t border-slate-100">
           <motion.div
             initial={{ opacity: 0, scale: 0.9 }}
             animate={{ opacity: 1, scale: 1 }}
