               Empowering future generations through clinical precision.
             </p>
           </motion.div>
        </div>
      </motion.div>
    );
  }

  return null;
};

export default Quiz;

import { useState, useMemo, useEffect } from 'react';
import { WellBeingLevel, Question, ResponseIndicator, StudentInfo, Submission, Option } from '../types';
import { api } from '../services/api';
import { motion, AnimatePresence } from 'framer-motion';

interface QuizProps {
  onComplete: (submission: Submission) => void;
}

type QuizStep = 'level-select' | 'student-info' | 'questions' | 'completed' | 'syncing';

const Quiz: React.FC<QuizProps> = ({ onComplete }) => {
  const [step, setStep] = useState<QuizStep>('level-select');
  const [questions, setQuestions] = useState<Question[]>([]);
  const [selectedLevel, setSelectedLevel] = useState<WellBeingLevel | null>(null);
  const [studentInfo, setStudentInfo] = useState<StudentInfo>({ name: '', age: '', standard: '', school: '' });
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<{ [id: string]: { indicator: ResponseIndicator; optionId: string } }>({});
  const [tempOption, setTempOption] = useState<Option | null>(null);
  const [finalSubmission, setFinalSubmission] = useState<Submission | null>(null);
  const [processingStatus, setProcessingStatus] = useState("Securing your data...");
  const [isTransitioning, setIsTransitioning] = useState(false);

  useEffect(() => {
    const load = async () => {
      const qData = await api.fetchQuestions();
      setQuestions(qData);
    };
    load();
  }, []);

  useEffect(() => {
    if (step === 'syncing') {
      const statuses = [
        "Analyzing clinical markers...",
        "Generating psychological synthesis...",
        "Checking risk indicators...",
        "Finalizing diagnostic report...",
        "Saving encrypted record..."
      ];
      let i = 0;
      const interval = setInterval(() => {
        setProcessingStatus(statuses[i % statuses.length]);
        i++;
      }, 1500);
      return () => clearInterval(interval);
    }
  }, [step]);

  const filteredQuestions = useMemo(() => {
    return questions.filter(q => q.level === selectedLevel);
  }, [selectedLevel, questions]);

  const progress = filteredQuestions.length > 0 
    ? Math.round(((currentQuestionIndex) / filteredQuestions.length) * 100) 
    : 0;

  const handleNext = async () => {
    if (!tempOption || isTransitioning) return;

    setIsTransitioning(true);

    const questionId = filteredQuestions[currentQuestionIndex].id;
    const newAnswers = { 
      ...answers, 
      [questionId]: { indicator: tempOption.indicator, optionId: tempOption.id } 
    };
    setAnswers(newAnswers);

    if (currentQuestionIndex < filteredQuestions.length - 1) {
      setTimeout(() => {
        setCurrentQuestionIndex(prev => prev + 1);
        setTempOption(null);
        setIsTransitioning(false);
      }, 300);
    } else {
      setStep('syncing');
      const answerList = Object.values(newAnswers).map(a => a.indicator);
      const { riskStatus, conclusion } = api.analyzeResults(answerList);

      const submission: Submission = {
        id: `sub_${Math.random().toString(36).substr(2, 9)}`,
        student: studentInfo,
        level: selectedLevel!,
        answers: newAnswers as any,
        metrics: {
          healthyCount: answerList.filter(v => v === ResponseIndicator.HEALTHY).length,
          concernCount: answerList.filter(v => v === ResponseIndicator.CONCERN).length,
          redFlagCount: answerList.filter(v => v === ResponseIndicator.RED_FLAG).length,
          totalQuestions: answerList.length
        },
        riskStatus,
        conclusion,
        timestamp: Date.now(),
      };

      try {
        const aiAnalysis = await api.generateAIAnalysis(submission, questions);
        submission.aiReport = aiAnalysis;
      } catch (e) {
        submission.aiReport = "Direct human review recommended.";
      }

      await api.submitAssessment(submission);
      setFinalSubmission(submission);
      setStep('completed');
      onComplete(submission);
      setIsTransitioning(false);
    }
  };

  if (step === 'syncing') {
    return (
      <motion.div 
        initial={{ opacity: 0 }} animate={{ opacity: 1 }}
        className="max-w-2xl mx-auto px-6 py-40 text-center"
      >
        <div className="relative mb-12">
           <div className="w-24 h-24 border-4 border-wellBeingBlue border-t-transparent rounded-full animate-spin mx-auto"></div>
           <div className="absolute inset-0 flex items-center justify-center">
             <div className="w-12 h-12 bg-wellBeingBlue/10 rounded-full animate-pulse"></div>
           </div>
        </div>
        <h2 className="text-4xl font-black text-slate-800 uppercase tracking-tighter mb-4">Processing Analysis</h2>
        <motion.p 
          key={processingStatus}
          initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }}
          className="text-slate-400 font-bold uppercase tracking-[0.3em] text-[12px]"
        >
          {processingStatus}
        </motion.p>
      </motion.div>
    );
  }

  if (step === 'level-select') {
    return (
      <div className="max-w-5xl mx-auto px-6 py-24">
        <div className="text-center mb-16">
          <h2 className="text-5xl md:text-6xl font-black text-wellBeingBlue tracking-tighter uppercase mb-6">Select Your Grade</h2>
          <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Choose the tier that fits your standard</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {Object.values(WellBeingLevel).map((level) => (
            <button
              key={level}
              onClick={() => { setSelectedLevel(level); setStep('student-info'); }}
              className="bg-white p-12 text-left group border border-slate-100 rounded-[3rem] hover:border-wellBeingBlue transition-all shadow-bento hover:shadow-xl"
            >
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-4xl font-black text-slate-800 group-hover:text-wellBeingBlue transition-colors tracking-tighter">{level}</h3>
                  <p className="text-[12px] font-black text-slate-400 uppercase tracking-[0.2em] mt-3">Interactive Self-Check</p>
                </div>
                <div className="w-16 h-16 rounded-full bg-slate-50 flex items-center justify-center text-slate-300 group-hover:bg-wellBeingBlue group-hover:text-white transition-all">
                  <span className="text-4xl font-bold">→</span>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  if (step === 'student-info') {
    return (
      <div className="max-w-2xl mx-auto px-6 py-24">
        <div className="bg-white p-12 shadow-soft-xl rounded-[3rem] border border-slate-100">
          <h2 className="text-4xl font-black text-slate-800 tracking-tighter uppercase mb-10 text-center">Student Details</h2>
          <form onSubmit={e => { e.preventDefault(); setStep('questions'); }} className="space-y-8">
            <div className="space-y-3">
               <label className="text-[12px] font-black uppercase text-gray-400 tracking-widest px-1">Full Name</label>
               <input required placeholder="Student Name" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-charcoal transition-all placeholder:text-gray-300 text-xl" onChange={e => setStudentInfo({...studentInfo, name: e.target.value})} />
            </div>
            <div className="grid grid-cols-2 gap-8">
               <div className="space-y-3">
                  <label className="text-[12px] font-black uppercase text-gray-400 tracking-widest px-1">Standard</label>
                  <input required placeholder="Class" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-charcoal transition-all placeholder:text-gray-300 text-xl" onChange={e => setStudentInfo({...studentInfo, standard: e.target.value})} />
               </div>
               <div className="space-y-3">
                  <label className="text-[12px] font-black uppercase text-gray-400 tracking-widest px-1">Age</label>
                  <input required type="number" placeholder="Age" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-charcoal transition-all placeholder:text-gray-300 text-xl" onChange={e => setStudentInfo({...studentInfo, age: e.target.value})} />
               </div>
            </div>
            <div className="space-y-3">
               <label className="text-[12px] font-black uppercase text-gray-400 tracking-widest px-1">School Name</label>
               <input required placeholder="Enter School" className="w-full px-8 py-5 rounded-[2rem] bg-slate-50 border border-transparent focus:bg-white focus:border-wellBeingBlue outline-none font-bold text-charcoal transition-all placeholder:text-gray-300 text-xl" onChange={e => setStudentInfo({...studentInfo, school: e.target.value})} />
            </div>
            <button type="submit" className="w-full mt-6 bg-wellBeingBlue text-white font-black py-7 rounded-full shadow-lg hover:shadow-wellBeingBlue/20 transition-all uppercase tracking-[0.2em] text-[13px]">Begin Diagnostic</button>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'questions') {
    const q = filteredQuestions[currentQuestionIndex];
    if (!q) return <div className="p-32 text-center font-black text-wellBeingBlue animate-pulse text-3xl">Initializing...</div>;

    const isLastQuestion = currentQuestionIndex === filteredQuestions.length - 1;

    return (
      <div className="max-w-6xl mx-auto px-6 py-4 md:py-6 flex flex-col min-h-[calc(100vh-140px)] justify-center">
        {/* Progress Header - More compact */}
        <div className="mb-6 flex flex-col md:flex-row items-center justify-between gap-4 shrink-0">
          <div className="flex items-center space-x-4">
            <span className="text-[10px] font-black text-white bg-wellBeingBlue uppercase tracking-[0.2em] px-6 py-2 rounded-full shadow-sm">{selectedLevel}</span>
            <span className="text-xs font-bold text-slate-400 uppercase tracking-[0.3em]">Module {currentQuestionIndex + 1} / {filteredQuestions.length}</span>
          </div>
          <div className="w-full md:w-64 bg-slate-200 rounded-full h-2 overflow-hidden">
            <div className="bg-wellBeingGreen h-full transition-all duration-700" style={{ width: `${progress}%` }}></div>
          </div>
        </div>

        <AnimatePresence mode="wait">
          <motion.div
            key={q.id}
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 1.02 }}
            transition={{ duration: 0.25 }}
            className="flex-grow flex flex-col justify-center"
          >
            {/* Professional Question Box - Optimized Padding for Zero Scroll */}
            <div className="bg-white p-10 md:p-14 rounded-[3.5rem] border border-slate-100 shadow-bento mb-8 text-center shrink-0">
                 <h2 className="text-4xl md:text-5xl font-black text-slate-800 leading-tight tracking-tighter mb-6">{q.textEn}</h2>
                 <div className="w-24 h-1.5 bg-wellBeingGreen/20 mx-auto mb-6 rounded-full"></div>
                 <h2 className="text-4xl md:text-5xl font-hindi font-bold text-wellBeingBlue leading-tight">{q.textHi}</h2>
            </div>

            {/* Compact Options Grid - Efficient vertical space usage */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8 shrink-0">
              {q.options.map(opt => (
                <button 
                  key={opt.id} 
                  disabled={isTransitioning}
                  onClick={() => setTempOption(opt)} 
                  className={`bg-white p-6 md:p-8 text-left group rounded-[2.5rem] border transition-all shadow-sm hover:shadow-md ${tempOption?.id === opt.id ? 'border-wellBeingGreen bg-wellBeingGreen/[0.03] ring-4 ring-wellBeingGreen/5 scale-[1.01]' : 'border-slate-50 hover:border-wellBeingGreen'}`}
                >
                  <div className="flex items-center space-x-6">
                    <div className={`w-12 h-12 md:w-14 md:h-14 shrink-0 rounded-full flex items-center justify-center font-black transition-all text-xl md:text-2xl ${tempOption?.id === opt.id ? 'bg-wellBeingGreen text-white' : 'bg-slate-50 text-wellBeingGreen group-hover:bg-wellBeingGreen group-hover:text-white'}`}>
                      {opt.id.toUpperCase()}
                    </div>
                    <div className="flex-grow">
                      <p className={`font-black text-xl md:text-2xl transition-colors tracking-tight leading-tight ${tempOption?.id === opt.id ? 'text-wellBeingGreen' : 'text-slate-800 group-hover:text-wellBeingGreen'}`}>{opt.en}</p>
                      <p className="text-slate-400 font-hindi font-bold text-base md:text-lg leading-relaxed italic mt-1">{opt.hi}</p>
                    </div>
                  </div>
                </button>
              ))}
            </div>
          </motion.div>
        </AnimatePresence>

        {/* Action Button Section - Fixed height at bottom */}
        <div className="flex justify-center h-20 shrink-0">
          <AnimatePresence>
            {tempOption && (
              <motion.button 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 10 }}
                disabled={isTransitioning}
                onClick={handleNext}
