        <div className="mb-6 flex flex-col md:flex-row items-center justify-between gap-4 shrink-0">
          <div className="flex items-center space-x-4">
            <span className="text-[10px] font-black text-white bg-wellBeingBlue uppercase tracking-[0.2em] px-6 py-2 rounded-full shadow-sm">{selectedLevel}</span>
            <span className="text-xs font-bold text-slate-400 uppercase tracking-[0.3em]">Progress: {currentQuestionIndex + 1} / {filteredQuestions.length}</span>
          </div>
          <div className="w-full md:w-64 bg-slate-200 rounded-full h-2 overflow-hidden">
            <div className="bg-wellBeingGreen h-full transition-all duration-700" style={{ width: `${progress}%` }}></div>
          </div>
        </div>

        <AnimatePresence mode="wait">
          <motion.div
            key={q.id}
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 1.02 }}
            transition={{ duration: 0.25 }}
            className="flex-grow flex flex-col justify-center overflow-hidden"
          >
            {/* Question Container - Zero Scroll Priority */}
            <div className="bg-white p-8 md:p-12 lg:p-14 rounded-[3.5rem] border border-slate-100 shadow-bento mb-6 text-center shrink-0">
                 <h2 className="text-3xl md:text-4xl lg:text-5xl font-black text-slate-800 leading-tight tracking-tighter mb-6">{q.textEn}</h2>
                 <div className="w-24 h-1.5 bg-wellBeingGreen/20 mx-auto mb-6 rounded-full"></div>
                 <h2 className="text-3xl md:text-4xl lg:text-5xl font-hindi font-bold text-wellBeingBlue leading-tight">{q.textHi}</h2>
            </div>

            {/* Options Grid - Compact & Responsive */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 lg:gap-6 mb-6 shrink-0">
              {q.options.map(opt => (
                <button 
                  key={opt.id} 
                  disabled={isTransitioning}
                  onClick={() => setTempOption(opt)} 
                  className={`bg-white p-5 md:p-6 lg:p-8 text-left group rounded-[2.5rem] border transition-all shadow-sm hover:shadow-md ${tempOption?.id === opt.id ? 'border-wellBeingGreen bg-wellBeingGreen/[0.03] ring-4 ring-wellBeingGreen/5 scale-[1.01]' : 'border-slate-50 hover:border-wellBeingGreen'}`}
                >
                  <div className="flex items-center space-x-5 lg:space-x-7">
                    <div className={`w-12 h-12 lg:w-14 lg:h-14 shrink-0 rounded-full flex items-center justify-center font-black transition-all text-xl lg:text-2xl ${tempOption?.id === opt.id ? 'bg-wellBeingGreen text-white' : 'bg-slate-50 text-wellBeingGreen group-hover:bg-wellBeingGreen group-hover:text-white'}`}>
                      {opt.id.toUpperCase()}
                    </div>
                    <div className="flex-grow">
                      <p className={`font-black text-lg lg:text-2xl transition-colors tracking-tight leading-tight ${tempOption?.id === opt.id ? 'text-wellBeingGreen' : 'text-slate-800 group-hover:text-wellBeingGreen'}`}>{opt.en}</p>
                      <p className="text-slate-400 font-hindi font-bold text-sm lg:text-lg leading-relaxed italic mt-1">{opt.hi}</p>
                    </div>
                  </div>
                </button>
              ))}
            </div>
          </motion.div>
        </AnimatePresence>

        {/* Footer Button - Fixed Position */}
        <div className="flex justify-center h-16 shrink-0 items-center">
          <AnimatePresence>
            {tempOption && (
              <motion.button 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 10 }}
                disabled={isTransitioning}
                onClick={handleNext}
                className={`px-16 md:px-24 py-4 md:py-6 rounded-full font-black uppercase tracking-[0.2em] text-[12px] transition-all shadow-xl bg-charcoal text-white hover:bg-black active:scale-95`}
