             <div className="w-12 h-12 bg-wellBeingBlue/10 rounded-full animate-pulse"></div>
           </div>
        </div>
        <h2 className="text-4xl font-black text-slate-800 uppercase tracking-tighter mb-4">Crafting Your Profile</h2>
        <motion.p 
          key={processingStatus}
          initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }}
          className="text-slate-400 font-bold uppercase tracking-[0.3em] text-[12px]"
        >
          {processingStatus}
        </motion.p>
      </motion.div>
    );
  }

  if (step === 'level-select') {
    return (
