                      {opt.id.toUpperCase()}
                    </div>
                    <div className="flex-grow">
                      <p className={`font-black text-lg md:text-xl lg:text-2xl transition-colors tracking-tight leading-tight ${tempOption?.id === opt.id ? 'text-wellBeingGreen' : 'text-slate-800 group-hover:text-wellBeingGreen'}`}>{opt.en}</p>
                      <p className="text-slate-400 font-hindi font-bold text-sm md:text-base lg:text-lg leading-relaxed italic mt-0.5 md:mt-1 opacity-80">{opt.hi}</p>
