                </div>
                <button onClick={() => setSelectedSubmission(null)} className="w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center">✕</button>
              </div>

              <div className="p-12 overflow-y-auto custom-scrollbar bg-slate-50/30 space-y-12">
                <div className="grid grid-cols-2 md:grid-cols-4 gap-8 bg-white p-10 rounded-[2.5rem] border border-slate-100">
                  <div>
                    <p className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Full Name</p>
                    <p className="font-bold text-slate-800">{selectedSubmission.student.name}</p>
                  </div>
                  <div>
                    <p className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Grade</p>
                    <p className="font-bold text-slate-800">Std {selectedSubmission.student.standard}</p>
                  </div>
                  <div>
                    <p className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Diagnostic ID</p>
                    <p className="font-bold text-wellBeingBlue">{selectedSubmission.id}</p>
                  </div>
                  <div>
                    <p className="text-[9px] font-black uppercase text-slate-400 tracking-widest">Status</p>
                    <p className={`font-black uppercase text-[10px] ${selectedSubmission.riskStatus === 'CRITICAL' ? 'text-red-500' : selectedSubmission.riskStatus === 'MODERATE' ? 'text-amber-500' : 'text-emerald-500'}`}>{selectedSubmission.riskStatus}</p>
                  </div>
                </div>

                {/* Feedback Display for Admin */}
                {selectedSubmission.feedback && (
                   <div className="bg-amber-50 border border-amber-100 p-8 rounded-[2.5rem]">
                      <h4 className="text-[10px] font-black uppercase text-amber-600 tracking-widest mb-4">Student Feedback / Self-Disclosure</h4>
                      <p className="font-medium text-slate-700 italic text-lg leading-relaxed">"{selectedSubmission.feedback}"</p>
                   </div>
                )}

                <div className="prose prose-slate prose-lg max-w-none">
                  <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-6">Psychological Synthesis</h4>
                  <div className="whitespace-pre-wrap font-medium text-slate-700 leading-relaxed text-lg border-l-4 border-wellBeingBlue/20 pl-8 py-2">
                    {selectedSubmission.aiReport ? selectedSubmission.aiReport : "Analysis pending or unavailable."}
                  </div>
                </div>
              </div>

              <div className="px-12 py-8 bg-white border-t border-slate-100 flex justify-between items-center shrink-0">
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Confidential • Authorized Review: {user.username}</p>
                <div className="flex gap-4">
                  <button disabled={isRegenerating} onClick={handleRegenerate} className={`flex items-center space-x-3 px-6 py-3 border-2 border-slate-100 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-600 ${isRegenerating ? 'opacity-50' : 'hover:border-wellBeingBlue hover:text-wellBeingBlue'}`}>
                    {isRegenerating ? <div className="w-4 h-4 border-2 border-wellBeingBlue border-t-transparent rounded-full animate-spin" /> : <span>🔄 Regenerate</span>}
                  </button>
                  <button onClick={() => window.print()} className="px-6 py-3 border-2 border-slate-200 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-600">Print</button>
                  <button onClick={() => setSelectedSubmission(null)} className="bg-charcoal text-white px-10 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-wellBeingBlue transition-all">Close</button>
                </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
};

