                    <div>
                      <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-1">Risk Verdict</p>
                      <div className={`text-xl font-black uppercase ${
                        selectedSubmission.riskStatus === 'CRITICAL' ? 'text-red-500' : 
