                      }`}>
                        {selectedSubmission.riskStatus}
                      </div>
                    </div>
                  </div>

                  {/* Student Feedback */}
                  {selectedSubmission.feedback && (
                    <div className="bg-amber-50/50 border border-amber-100 p-8 rounded-[2.5rem]">
